CREATE TABLE IF NOT EXISTS gda_relationships (id SERIAL PRIMARY KEY, name TEXT NOT NULL, title TEXT, organization TEXT, agency TEXT, email TEXT, phone TEXT, relationship_strength INTEGER DEFAULT 1 CHECK (relationship_strength BETWEEN 1 AND 10), last_contact_date DATE, contact_frequency_days INTEGER DEFAULT 90, notes TEXT, tags TEXT[], gda_unit TEXT, related_opps INTEGER[], created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS gda_touchpoints (id SERIAL PRIMARY KEY, relationship_id INTEGER REFERENCES gda_relationships(id), contact_type TEXT, summary TEXT, next_action TEXT, next_action_date DATE, created_at TIMESTAMPTZ DEFAULT NOW());
SELECT r.*, (SELECT COUNT(*) FROM gda_touchpoints t WHERE t.relationship_id = r.id) as touchpoint_count, (SELECT MAX(t.created_at) FROM gda_touchpoints t WHERE t.relationship_id = r.id) as last_touchpoint FROM gda_relationships r ORDER BY r.relationship_strength DESC, r.last_contact_date ASC
